// Runtime expansion function to populate fully detailed Medicine records
export function getAdditionalMedicines(): Medicine[] {
  const lines = RAW_MEDS_DATA.split("\n");
  const list: Medicine[] = [];
  
  lines.forEach((line, idx) => {
    const parts = line.split("|");
    if (parts.length < 4) return;

    const namesPart = parts[0].trim();
    // Parse name structures such as "ABACAVIR = ABC"
    const genericName = namesPart.split(" = ")[0].trim();
    
    // Brand names parsing
    const brandStr = parts[1].trim();
    const brandNames = brandStr ? brandStr.split(",").map(b => b.trim()) : [];
    
    // Add abbreviations as brand names too if present
    if (namesPart.includes("=")) {
      namesPart.split("=").slice(1).forEach(item => {
        const abb = item.trim();
        if (abb && !brandNames.includes(abb)) brandNames.push(abb);
      });
    }

    const category = parts[2].trim() as MedicineCategory;
    
    // Clinical indicators or defaults
    const ind = parts[3].trim();
    const contra = parts[4]?.trim() || "Hipersensibilidad conocida al principio activo.";
    const dosage = parts[5]?.trim() || "Según pauta médica e indicación clínica.";
    const presentation = parts[6]?.trim() || "Comprimidos de dosificación estándar.";
    const ram = parts[7]?.trim() || "Náuseas, malestar transitorio o cefalea.";
    const warnings = parts[8]?.trim() || "Administrar bajo estricta supervisión facultativa.";

    const isCritical = warnings.toLowerCase().includes("crítica:") || 
                       category === "Cardiovascular e Inotrópicos" || 
                       category === "Anticoagulantes y Hemostáticos" ||
                       category === "Anestésicos y Sedantes" ||
                       genericName.toLowerCase().includes("antitetánico") ||
                       genericName.toLowerCase().includes("adrenalina") ||
                       genericName.toLowerCase().includes("insulina");

    const id = 34 + idx;

    const med: Medicine = {
      id,
      fullName: `${genericName} ${brandNames.length > 0 ? `(${brandNames.join(", ")})` : ""}`,
      genericName,
      brandNames,
      composition: `Principio de alta fidelidad ${genericName}.`,
      indications: ind,
      contraindications: contra,
      dosage,
      presentation,
      adverseReactions: ram,
      warningsPrecautions: warnings,
      category,
      isCritical
    };

    list.push(med);
  });

  return list;
}
